import{_ as e,o as t,c as l,a3 as r}from"./chunks/framework.q4B3G9ZH.js";const h=JSON.parse('{"title":"透明渲染","description":"","frontmatter":{},"headers":[],"relativePath":"图形学/透明渲染.md","filePath":"图形学/透明渲染.md","lastUpdated":null}'),o={name:"图形学/透明渲染.md"};function d(i,a,n,p,c,s){return t(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="透明渲染" tabindex="-1">透明渲染 <a class="header-anchor" href="#透明渲染" aria-label="Permalink to &quot;透明渲染&quot;">​</a></h1><h2 id="透明测试" tabindex="-1">透明测试 <a class="header-anchor" href="#透明测试" aria-label="Permalink to &quot;透明测试&quot;">​</a></h2><p>和深度测试的思路类似，剔除某些小于透明阈值的像素，实现某些位置完全透明，我们设定一个alpha阈值，当片元不满足条件（通常是小于阈值）就直接舍弃当作全透明，满足条件的片元就直接当作不透明物体进行处理。所以注意AlphaTest并没有实现真正的半透明效果。</p><h2 id="混合透明效果" tabindex="-1">混合透明效果 <a class="header-anchor" href="#混合透明效果" aria-label="Permalink to &quot;混合透明效果&quot;">​</a></h2><p>将新渲染出来的图像和已存在的进行合并。</p><p>常用的混合模式有：</p><ul><li>Blend Off 关闭混合处理。</li><li>Blend SrcFactor DstFactor 开启混合处理，自定义混合模式，将目标图像（新渲染出的图像）和源图像（已存在的图像）按照混合系数进行rgba四通道的加权混合。</li><li>Blend SrcFactor DstFactor,SrcFactorA DstFactorA 与上条类似，只不过分别计算rgb通道和alpha通道的混合。</li><li>BlendOp Op：使用逻辑操作指令指定加权后的图像像素值具体如何混合，比如Add，Sub等（默认不写为Add）。</li><li>BlendOp OpColor，OpAlpha： 使用逻辑操作，分别计算rgb通道和alpha通道。</li></ul><p>注意，先用BlendOp声明逻辑操作类型，在用Blend声明混合系数。</p>',8)])])}const u=e(o,[["render",d]]);export{h as __pageData,u as default};
